mapper.select:
SELECT DATE_FORMAT(s.next_billing_at, '%Y-%m-%d') AS date, COUNT(*) AS count, COALESCE(SUM(p.price), 0) AS amount FROM SUBSCRIPTION s JOIN SUBSCRIPTION_PLAN p ON s.plan_id = p.id JOIN MEMBER mb ON s.member_id = mb.id WHERE s.status = 'ACTIVE' AND s.next_billing_at BETWEEN #{from} AND #{to}
AND mb.church_id = #{churchId}
GROUP BY DATE_FORMAT(s.next_billing_at, '%Y-%m-%d') ORDER BY date
